CREATE OR REPLACE FUNCTION "audit"."trg_fn_audit_actor"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'actors'
    AS $$
BEGIN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        PERFORM "audit"."log_event"(
            'actor_status_changed',
            'actors', 'actors', NEW.id,
            NULL, NEW.id,
            jsonb_build_object('old_status', OLD.status::text, 'new_status', NEW.status::text),
            CASE WHEN NEW.status::text = 'suspended' THEN 'warn' ELSE 'info' END
        );
    END IF;
    RETURN NEW;
END;
$$;


