CREATE OR REPLACE FUNCTION "audit"."trg_fn_audit_lenser_profile"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'lensers'
    AS $$
BEGIN
    IF TG_OP = 'UPDATE' AND OLD.status IS DISTINCT FROM NEW.status THEN
        PERFORM "audit"."log_event"(
            'lenser_profile_status_changed',
            'lensers', 'profiles', NEW.id,
            NEW.id, NULL,
            jsonb_build_object('old_status', OLD.status, 'new_status', NEW.status),
            CASE WHEN NEW.status IN ('suspended','deleted') THEN 'warn' ELSE 'info' END
        );
    END IF;

    IF TG_OP = 'DELETE' THEN
        PERFORM "audit"."log_event"(
            'lenser_profile_deleted',
            'lensers', 'profiles', OLD.id,
            OLD.id, NULL,
            jsonb_build_object('deleted_status', OLD.status),
            'warn'
        );
    END IF;

    RETURN COALESCE(NEW, OLD);
END;
$$;


