CREATE OR REPLACE FUNCTION "audit"."trg_workflow_run_lifecycle_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'lenses', 'lensers', 'public'
    AS $$
BEGIN
  -- Log on INSERT (run creation)
  IF TG_OP = 'INSERT' THEN
    INSERT INTO audit.events (
      event_type,
      entity_schema,
      entity_table,
      entity_id,
      actor_lenser_id,
      payload
    ) VALUES (
      'workflow_run_created',
      'lenses',
      'workflow_runs',
      NEW.id,
      NEW.triggered_by,
      jsonb_build_object(
        'workflow_id',     NEW.workflow_id,
        'status',          NEW.status,
        'global_model_id', NEW.global_model_id,
        'budget_credits',  NEW.budget_credits
      )
    );
  END IF;

  -- Log on status change
  IF TG_OP = 'UPDATE' AND OLD.status <> NEW.status THEN
    INSERT INTO audit.events (
      event_type,
      entity_schema,
      entity_table,
      entity_id,
      actor_lenser_id,
      payload
    ) VALUES (
      'workflow_run_' || NEW.status,
      'lenses',
      'workflow_runs',
      NEW.id,
      NEW.triggered_by,
      jsonb_build_object(
        'workflow_id',     NEW.workflow_id,
        'old_status',      OLD.status,
        'new_status',      NEW.status,
        'global_model_id', NEW.global_model_id,
        'budget_credits',  NEW.budget_credits,
        'spent_credits',   NEW.spent_credits
      )
    );
  END IF;

  RETURN NEW;
END;
$$;


