    AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        RAISE EXCEPTION 'Battle events are immutable. Deletion is not permitted.';
    ELSIF TG_OP = 'UPDATE' THEN
        RAISE EXCEPTION 'Battle events are immutable. Updates are not permitted.';
    END IF;
    RETURN NULL;
END;
$$;


