CREATE OR REPLACE FUNCTION "battles"."trg_prevent_self_vote"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
    -- Check if voter is a contender in this battle (by lenser_id only)
    IF EXISTS (
        SELECT 1 FROM battles.contenders c
        WHERE c.battle_id = NEW.battle_id
          AND c.contender_type = 'human'
          AND c.contender_ref_id = NEW.voter_lenser_id
    ) THEN
        RAISE EXCEPTION 'SELF_VOTE_BLOCKED: Contenders cannot vote on their own battle (voter_lenser_id=%, battle_id=%)',
            NEW.voter_lenser_id, NEW.battle_id;
    END IF;

    RETURN NEW;
END;
$$;


