CREATE OR REPLACE FUNCTION "content"."sync_lens_count"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'analytics'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_lenser_id := NEW.lenser_id;
  ELSIF TG_OP = 'DELETE' THEN
    v_lenser_id := OLD.lenser_id;
  ELSE
    RETURN NULL;
  END IF;

  UPDATE analytics.lenser_stats e
  SET lens_count = (
        SELECT COUNT(*)::int
        FROM lenses.lenses p
        WHERE p.lenser_id = v_lenser_id
      ),
      updated_at = now()
  WHERE e.lenser_id = v_lenser_id;

  RETURN NULL;
END;
