CREATE TABLE IF NOT EXISTS "analytics"."shared_links" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "short_id" "text" NOT NULL,
    "resource_type" "text" NOT NULL,
    "resource_id" "uuid" NOT NULL,
    "slug" "text",
    "creator_lenser_id" "uuid",
    "channel" "text" DEFAULT 'in_app'::"text" NOT NULL,
    "campaign_key" "text",
    "experiment_key" "text",
    "experiment_variant" "text",
    "meta" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "display_name" "text",
    "expires_at" timestamp with time zone,
    "max_uses" integer,
    "use_count" integer DEFAULT 0 NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL
);


ALTER TABLE "analytics"."shared_links" OWNER TO "postgres";


COMMENT ON TABLE "analytics"."shared_links" IS 'Configuration for shareable short links in LenserFight (per resource, per Lenser, per campaign).';



COMMENT ON COLUMN "analytics"."shared_links"."creator_lenser_id" IS 'FK to lensers.id; used for RLS (each Lenser sees only their own links).';



COMMENT ON COLUMN "analytics"."shared_links"."expires_at" IS 'When this link expires. NULL = no expiry. Used for invitation links.';



COMMENT ON COLUMN "analytics"."shared_links"."max_uses" IS 'Maximum number of times this link can be consumed. NULL = unlimited.';



COMMENT ON COLUMN "analytics"."shared_links"."use_count" IS 'Number of times this link has been consumed. Incremented by fn_analytics_shared_links_consume.';



COMMENT ON COLUMN "analytics"."shared_links"."is_active" IS 'Whether this link is active. Deactivated links return 410 Gone.';



CREATE OR REPLACE FUNCTION "public"."fn_analytics_shared_links_consume"("p_short_id" "text") RETURNS "analytics"."shared_links"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics'
    AS $$
DECLARE
    v_link analytics.shared_links;
BEGIN
    SELECT * INTO v_link
    FROM analytics.shared_links
    WHERE short_id = p_short_id;

    IF v_link.id IS NULL THEN
        RAISE EXCEPTION 'Shared link not found';
    END IF;

    IF NOT v_link.is_active THEN
        RAISE EXCEPTION 'Link is no longer active';
    END IF;

    IF v_link.expires_at IS NOT NULL AND now() > v_link.expires_at THEN
        UPDATE analytics.shared_links SET is_active = false WHERE id = v_link.id;
        RAISE EXCEPTION 'Link has expired';
    END IF;

    IF v_link.max_uses IS NOT NULL AND v_link.use_count >= v_link.max_uses THEN
        UPDATE analytics.shared_links SET is_active = false WHERE id = v_link.id;
        RAISE EXCEPTION 'Link usage limit reached';
    END IF;

    -- Increment use count
    UPDATE analytics.shared_links
    SET use_count = use_count + 1,
        is_active = CASE
            WHEN max_uses IS NOT NULL AND use_count + 1 >= max_uses THEN false
            ELSE is_active
        END
    WHERE id = v_link.id
    RETURNING * INTO v_link;

    RETURN v_link;
END;
$$;


ALTER FUNCTION "public"."fn_analytics_shared_links_consume"("p_short_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_analytics_shared_links_create"("p_resource_type" "text", "p_resource_id" "text" DEFAULT NULL::"text", "p_slug" "text" DEFAULT NULL::"text", "p_channel" "text" DEFAULT 'in_app'::"text", "p_meta" "jsonb" DEFAULT '{}'::"jsonb", "p_display_name" "text" DEFAULT NULL::"text", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_max_uses" integer DEFAULT NULL::integer) RETURNS "analytics"."shared_links"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'lensers', 'auth'
    AS $$
DECLARE
    v_user_id       uuid;
    v_lenser_id     uuid;
    v_resource_uuid uuid;
    v_short_id      text;
    v_new           analytics.shared_links;
    v_handle        text;
    v_recent_count  integer;
BEGIN
    -- 1. Identify the creator from JWT
    BEGIN
        v_user_id := (auth.jwt() ->> 'sub')::uuid;
    EXCEPTION WHEN OTHERS THEN
        v_user_id := NULL;
    END;

    IF v_user_id IS NOT NULL THEN
        SELECT id, handle INTO v_lenser_id, v_handle
        FROM lensers.profiles
        WHERE user_id = v_user_id;
    END IF;

    -- 2. Anti-abuse rate limiting
    SELECT COUNT(*) INTO v_recent_count
    FROM analytics.shared_links
    WHERE creator_lenser_id = v_lenser_id
      AND created_at > now() - interval '1 hour';

    IF v_recent_count >= 100 THEN
        RAISE EXCEPTION 'Rate limit exceeded: too many shared links created recently';
    END IF;

    -- 3. Validate resource_type
    IF p_resource_type NOT IN (
        'thread', 'lens', 'battle', 'profile', 'tag',
        'group_invite', 'org_member_invite', 'battle_invite'
    ) THEN
        RAISE EXCEPTION 'Invalid resource_type: %', p_resource_type;
    END IF;

    -- 4. Parse and validate resource_id
    IF p_resource_id IS NOT NULL THEN
        BEGIN
            v_resource_uuid := p_resource_id::uuid;
        EXCEPTION WHEN OTHERS THEN
            RAISE EXCEPTION 'Invalid resource_id format: must be a valid UUID';
        END;

        -- Validate resource exists for invitation types
        IF p_resource_type = 'group_invite' THEN
            IF NOT EXISTS (SELECT 1 FROM lensers.groups WHERE id = v_resource_uuid) THEN
                RAISE EXCEPTION 'Group not found: %', v_resource_uuid;
            END IF;
        ELSIF p_resource_type = 'org_member_invite' THEN
            IF NOT EXISTS (SELECT 1 FROM organizations.organizations WHERE id = v_resource_uuid) THEN
                RAISE EXCEPTION 'Organization not found: %', v_resource_uuid;
            END IF;
        ELSIF p_resource_type = 'battle_invite' THEN
            IF NOT EXISTS (SELECT 1 FROM battles.battles WHERE id = v_resource_uuid) THEN
                RAISE EXCEPTION 'Battle not found: %', v_resource_uuid;
            END IF;
        END IF;
    END IF;

    -- 5. Generate short_id (using gen_random_uuid to avoid pgcrypto dependency)
    v_short_id := replace(gen_random_uuid()::text, '-', '');
    v_short_id := substr(v_short_id, 1, 8);

    -- 6. Insert shared link
    INSERT INTO analytics.shared_links (
        short_id, resource_type, resource_id, slug,
        creator_lenser_id, channel, meta, display_name,
        expires_at, max_uses
    )
    VALUES (
        v_short_id, p_resource_type, v_resource_uuid, p_slug,
        v_lenser_id, p_channel, p_meta,
        COALESCE(p_display_name, v_handle),
        p_expires_at, p_max_uses
    )
    RETURNING * INTO v_new;

    RETURN v_new;
END;
$$;


ALTER FUNCTION "public"."fn_analytics_shared_links_create"("p_resource_type" "text", "p_resource_id" "text", "p_slug" "text", "p_channel" "text", "p_meta" "jsonb", "p_display_name" "text", "p_expires_at" timestamp with time zone, "p_max_uses" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_analytics_shared_links_create"("p_resource_type" "text", "p_resource_id" "text", "p_slug" "text", "p_channel" "text", "p_meta" "jsonb", "p_display_name" "text", "p_expires_at" timestamp with time zone, "p_max_uses" integer) IS 'Creates a shared or invitation link. Supports group_invite, org_member_invite, and battle_invite resource types. Added p_expires_at and p_max_uses in migration 000030. 6-param overload removed in migration 000054 to resolve PostgREST 42725 ambiguity. SECURITY DEFINER — rate-limited to 100 links/hour per lenser.';



