CREATE OR REPLACE FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_creator_id uuid;
BEGIN
  SELECT id INTO v_creator_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_creator_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated.';
  END IF;

  UPDATE battles.battles
  SET
    status           = 'scoring',
    voting_closes_at = now(),
    updated_at       = now()
  WHERE id                = p_battle_id
    AND creator_lenser_id = v_creator_id
    AND status            = 'voting'
    AND deleted_at        IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found, not owned by you, or not in voting status.';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") IS 'Transitions a battle from voting to scoring. Sets voting_closes_at = now(). Only callable by the battle creator. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_creator_id     uuid;
  v_accepted_count int;
BEGIN
  SELECT id INTO v_creator_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_creator_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated.';
  END IF;

  -- Require at least 2 accepted contenders before voting can open
  SELECT COUNT(*) INTO v_accepted_count
  FROM battles.contenders
  WHERE battle_id        = p_battle_id
    AND contender_status = 'accepted';

  IF v_accepted_count < 2 THEN
    RAISE EXCEPTION 'Battle must have at least 2 accepted contenders before voting can open.';
  END IF;

  UPDATE battles.battles
  SET
    status          = 'voting',
    voting_opens_at = now(),
    updated_at      = now()
  WHERE id                = p_battle_id
    AND creator_lenser_id = v_creator_id
    AND status            = 'open'
    AND deleted_at        IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found, not owned by you, or not in open status.';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") IS 'Transitions a battle from open to voting. Requires at least 2 accepted contenders. Sets voting_opens_at = now(). Only callable by the battle creator. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_archive"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id != v_lenser_id THEN
        RAISE EXCEPTION 'Only the battle creator can archive';
    END IF;

    IF v_battle.status NOT IN ('closed', 'published') THEN
        RAISE EXCEPTION 'Battle must be closed or published to archive (current: %)', v_battle.status;
    END IF;

    UPDATE battles.battles
    SET status = 'archived',
        updated_at = now()
    WHERE id = p_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_archive"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_clone"("p_battle_id" "uuid", "p_title" "text", "p_slug" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_source RECORD;
    v_new_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_source
    FROM battles.battles
    WHERE id = p_battle_id
      AND deleted_at IS NULL;

    IF v_source IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    INSERT INTO battles.battles (
        creator_lenser_id, title, slug, task_prompt,
        rubric_id, status, max_contenders
    )
    VALUES (
        v_lenser_id, p_title, p_slug, v_source.task_prompt,
        v_source.rubric_id, 'draft', v_source.max_contenders
    )
    RETURNING id INTO v_new_id;

    -- Log the event
    INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
    VALUES (
        v_new_id,
        'status_change',
        v_lenser_id,
        jsonb_build_object('action', 'cloned', 'source_battle_id', p_battle_id)
    );

    RETURN v_new_id;
END;
$$;


