CREATE OR REPLACE VIEW "battles"."v_battle_full" AS
 SELECT "b"."id",
    "b"."slug",
    "b"."title",
    "b"."task_prompt",
    "b"."status",
    "b"."battle_type",
    "b"."voter_eligibility",
    "b"."handicap_config",
    "b"."max_contenders",
    "b"."rubric_id",
    "b"."total_vote_count",
    "b"."published_at",
    "b"."voting_opens_at",
    "b"."voting_closes_at",
    "b"."finalized_at",
    "b"."winner_contender_id",
    "b"."creator_lenser_id",
    "b"."created_at",
    "b"."updated_at",
    "ca"."id" AS "contender_a_id",
    "ca"."display_name" AS "contender_a_name",
    "ca"."contender_type" AS "contender_a_type",
    "ca"."contender_status" AS "contender_a_status",
    "ema"."profile_id" AS "contender_a_profile_id",
    "ema"."ai_lenser_id" AS "contender_a_ai_lenser_id",
    "sa"."id" AS "submission_a_id",
    "sa"."content_text" AS "submission_a_text",
    "sa"."content_url" AS "submission_a_url",
    "sa"."status" AS "submission_a_status",
    "va"."raw_vote_count" AS "votes_a",
    "va"."weighted_vote_sum" AS "score_a",
    "va"."draw_count" AS "draw_count_a",
    "cb"."id" AS "contender_b_id",
    "cb"."display_name" AS "contender_b_name",
    "cb"."contender_type" AS "contender_b_type",
    "cb"."contender_status" AS "contender_b_status",
    "emb"."profile_id" AS "contender_b_profile_id",
    "emb"."ai_lenser_id" AS "contender_b_ai_lenser_id",
    "sb"."id" AS "submission_b_id",
    "sb"."content_text" AS "submission_b_text",
    "sb"."content_url" AS "submission_b_url",
    "sb"."status" AS "submission_b_status",
    "vb"."raw_vote_count" AS "votes_b",
    "vb"."weighted_vote_sum" AS "score_b",
        CASE
            WHEN ("b"."winner_contender_id" = "ca"."id") THEN 'A'::"text"
            WHEN ("b"."winner_contender_id" = "cb"."id") THEN 'B'::"text"
            ELSE NULL::"text"
        END AS "winner_slot",
    "rs"."snapshot_hash" AS "rule_snapshot_hash"
   FROM ((((((((("battles"."battles" "b"
     LEFT JOIN "battles"."contenders" "ca" ON ((("ca"."battle_id" = "b"."id") AND ("ca"."slot" = 'A'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "ema" ON (("ema"."contender_id" = "ca"."id")))
     LEFT JOIN "battles"."submissions" "sa" ON ((("sa"."contender_id" = "ca"."id") AND ("sa"."is_final" = true) AND ("sa"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "va" ON ((("va"."battle_id" = "b"."id") AND ("va"."contender_id" = "ca"."id"))))
     LEFT JOIN "battles"."contenders" "cb" ON ((("cb"."battle_id" = "b"."id") AND ("cb"."slot" = 'B'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "emb" ON (("emb"."contender_id" = "cb"."id")))
     LEFT JOIN "battles"."submissions" "sb" ON ((("sb"."contender_id" = "cb"."id") AND ("sb"."is_final" = true) AND ("sb"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "vb" ON ((("vb"."battle_id" = "b"."id") AND ("vb"."contender_id" = "cb"."id"))))
     LEFT JOIN LATERAL ( SELECT "rule_snapshots"."snapshot_hash"
           FROM "battles"."rule_snapshots"
          WHERE ("rule_snapshots"."battle_id" = "b"."id")
          ORDER BY "rule_snapshots"."created_at" DESC
         LIMIT 1) "rs" ON (true))
  WHERE ("b"."deleted_at" IS NULL);


ALTER VIEW "battles"."v_battle_full" OWNER TO "postgres";


COMMENT ON VIEW "battles"."v_battle_full" IS 'Full battle lobby state for BattleDetailPage. Used by fn_get_battle_full. Covers contenders, entity map, final submissions, vote aggregates, and rule snapshot hash in a single join. contender_entity_map is the canonical identity source for slot resolution.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_full"("p_slug" "text") RETURNS "battles"."v_battle_full"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT *
  FROM battles.v_battle_full
  WHERE slug = p_slug
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_battle_full"("p_slug" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battle_full"("p_slug" "text") IS 'Returns full battle state for BattleDetailPage by slug. Single roundtrip covers contenders, submissions, vote aggregates, entity map, and rule snapshot hash via v_battle_full view.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battles_feed"("p_status" "text" DEFAULT NULL::"text", "p_battle_type" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20, "p_cursor" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "status" "text", "published_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "total_vote_count" integer, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "contender_a_id" "uuid", "contender_a_name" "text", "contender_a_type" "text", "contender_b_id" "uuid", "contender_b_name" "text", "contender_b_type" "text", "winner_slot" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    v.id,
    v.slug,
    v.title,
    v.status::text,
    v.published_at,
    v.battle_type::text,
    v.voter_eligibility::text,
    v.total_vote_count,
    v.voting_opens_at,
    v.voting_closes_at,
    v.contender_a_id,
    v.contender_a_name,
    v.contender_a_type::text,
    v.contender_b_id,
    v.contender_b_name,
    v.contender_b_type::text,
    v.winner_slot
  FROM battles.v_battle_feed_item v
  WHERE
    -- Defence-in-depth: always exclude draft/open regardless of p_status parameter
    v.status::text IN ('voting', 'scoring', 'closed', 'published', 'archived')
    AND (p_status IS NULL      OR v.status::text      = p_status)
    AND (p_battle_type IS NULL OR v.battle_type::text = p_battle_type)
    AND (p_cursor IS NULL      OR v.published_at < p_cursor)
  ORDER BY v.published_at DESC NULLS LAST
  LIMIT LEAST(COALESCE(p_limit, 20), 100);
$$;


ALTER FUNCTION "public"."fn_get_battles_feed"("p_status" "text", "p_battle_type" "text", "p_limit" integer, "p_cursor" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battles_feed"("p_status" "text", "p_battle_type" "text", "p_limit" integer, "p_cursor" timestamp with time zone) IS 'Paginated battle feed. Filters by status and battle_type (both optional text). Always excludes draft/open battles. Keyset pagination via p_cursor (published_at of last item). LIMIT capped at 100. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_get_global_messages"("p_battle_id" "uuid", "p_limit" integer DEFAULT 50, "p_before_ts" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "sender_id" "uuid", "sender_handle" "text", "sender_role" "text", "body" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
  SELECT
    id,
    battle_id,
    sender_id,
    sender_handle,
    sender_role,
    body,
    created_at
  FROM battles.global_messages
  WHERE battle_id = p_battle_id
    AND (
      p_before_ts IS NULL
      OR (created_at, id) < (p_before_ts, p_before_id)
    )
  ORDER BY created_at DESC, id DESC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."fn_get_global_messages"("p_battle_id" "uuid", "p_limit" integer, "p_before_ts" timestamp with time zone, "p_before_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "lensers"."profiles" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "user_id" "uuid" DEFAULT "auth"."uid"(),
    "handle" "text" NOT NULL,
    "display_name" "text" NOT NULL,
    "bio" "text",
    "headline" "text",
    "avatar_url" "text",
    "banner_url" "text",
    "location" "text",
    "website_url" "text",
    "status" "lensers"."lenser_status" DEFAULT 'active'::"lensers"."lenser_status" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "visibility" "lensers"."lenser_visibility" DEFAULT 'public'::"lensers"."lenser_visibility",
    "is_in_waiting_list" boolean DEFAULT false,
    "deletion_requested_at" timestamp with time zone,
    "last_handle_changed_at" timestamp with time zone,
    "join_order" bigint,
    "last_login_at" timestamp with time zone,
    "last_active_at" timestamp with time zone,
    "login_count" integer DEFAULT 0,
    "onboarding_step" smallint DEFAULT 0 NOT NULL,
    "onboarding_completed_at" timestamp with time zone,
    "type" "lensers"."lenser_type" DEFAULT 'human'::"lensers"."lenser_type" NOT NULL,
    "ai_model_id" "uuid",
    "deletion_deadline_at" timestamp with time zone,
    CONSTRAINT "lensers_handle_format_check" CHECK ((("handle" = "lower"("handle")) AND ("handle" ~ '^[a-z0-9._]+$'::"text") AND (("char_length"("handle") >= 4) AND ("char_length"("handle") <= 24)))),
    CONSTRAINT "lensers_reserved_handle_check" CHECK (("lower"("handle") <> ALL (ARRAY['lenser'::"text", 'lens'::"text", 'lena'::"text", 'lensa'::"text", 'lense'::"text", 'leni'::"text", 'len'::"text", 'lensizm'::"text"]))),
    CONSTRAINT "lensers_website_url_format_check" CHECK ((("website_url" IS NULL) OR ("website_url" ~ '^https?:\/\/[A-Za-z0-9.-]+\.[A-Za-z]{2,}.*$'::"text")))
);


ALTER TABLE "lensers"."profiles" OWNER TO "postgres";


COMMENT ON COLUMN "lensers"."profiles"."onboarding_step" IS '0=not started, 1=handle/profile created, 2=preferences set (complete)';



COMMENT ON COLUMN "lensers"."profiles"."onboarding_completed_at" IS 'Timestamp when all onboarding steps were finished; NULL means incomplete.';



CREATE TABLE IF NOT EXISTS "reputation"."contender_ratings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "category" "text" NOT NULL,
    "elo_rating" numeric(10,4) DEFAULT 1000 NOT NULL,
    "uncertainty" numeric(10,4) DEFAULT 350 NOT NULL,
    "battles_played" integer DEFAULT 0 NOT NULL,
    "wins" integer DEFAULT 0 NOT NULL,
    "draws" integer DEFAULT 0 NOT NULL,
    "losses" integer DEFAULT 0 NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "sigma" numeric(10,6) DEFAULT 0.06 NOT NULL,
    "tau" numeric(10,6) DEFAULT 0.0833 NOT NULL,
    "beta" numeric(10,6) DEFAULT 4.1667 NOT NULL,
    CONSTRAINT "contender_ratings_draws_nonneg" CHECK (("draws" >= 0)),
    CONSTRAINT "contender_ratings_losses_nonneg" CHECK (("losses" >= 0)),
    CONSTRAINT "contender_ratings_played_nonneg" CHECK (("battles_played" >= 0)),
    CONSTRAINT "contender_ratings_wins_nonneg" CHECK (("wins" >= 0))
);


ALTER TABLE "reputation"."contender_ratings" OWNER TO "postgres";


COMMENT ON TABLE "reputation"."contender_ratings" IS 'Per-category ELO battle performance. One row per (lenser_id, category). battles_played = wins + draws + losses must hold after each update (enforced by the trigger, not a CHECK constraint). category is free text to avoid enum rigidity; standardize via app logic.';



COMMENT ON COLUMN "reputation"."contender_ratings"."sigma" IS 'Glicko-2 volatility σ (default 0.06). Updated after each battle via fn_update_elo_on_finalize.';



COMMENT ON COLUMN "reputation"."contender_ratings"."tau" IS 'TrueSkill dynamics factor (sigma/3): models skill drift over time between battles.';



COMMENT ON COLUMN "reputation"."contender_ratings"."beta" IS 'TrueSkill performance variance: models the randomness of a single game performance.';



CREATE TABLE IF NOT EXISTS "reputation"."lenser_scores" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "score_type" "text" NOT NULL,
    "score" numeric(10,4) DEFAULT 1000 NOT NULL,
    "uncertainty" numeric(10,4) DEFAULT 350 NOT NULL,
    "computed_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "lenser_scores_type_check" CHECK (("score_type" = ANY (ARRAY['elo'::"text", 'trust'::"text", 'composite'::"text"])))
);


ALTER TABLE "reputation"."lenser_scores" OWNER TO "postgres";


COMMENT ON TABLE "reputation"."lenser_scores" IS 'Overall reputation score per lenser. One row per (lenser_id, score_type). Updated by service_role after battle finalization or scheduled recomputation. uncertainty is the Glicko-2 rating deviation (RD): lower = more confident.';



CREATE TABLE IF NOT EXISTS "xp"."totals" (
    "lenser_id" "uuid" NOT NULL,
    "app_id" "uuid" NOT NULL,
    "total_xp" bigint DEFAULT 0 NOT NULL,
    "current_level" integer DEFAULT 1 NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "xp"."totals" OWNER TO "postgres";


CREATE OR REPLACE VIEW "xp"."v_leaderboard" AS
 SELECT "p"."id" AS "lenser_id",
    "p"."handle",
    "p"."display_name",
    "p"."avatar_url",
    "p"."type" AS "lenser_type",
    COALESCE("xt"."total_xp", (0)::bigint) AS "total_xp",
    COALESCE("xt"."current_level", 1) AS "current_level",
    COALESCE("rs_elo"."score", (1000)::numeric) AS "elo_score",
    COALESCE("rs_cmp"."score", (1000)::numeric) AS "composite_score",
    COALESCE("sum"("cr"."battles_played"), (0)::bigint) AS "battles_played",
    COALESCE("sum"("cr"."wins"), (0)::bigint) AS "battles_won",
    "dense_rank"() OVER (ORDER BY COALESCE("xt"."total_xp", (0)::bigint) DESC) AS "xp_rank",
    "dense_rank"() OVER (ORDER BY COALESCE("rs_elo"."score", (1000)::numeric) DESC) AS "elo_rank"
   FROM (((("lensers"."profiles" "p"
     LEFT JOIN "xp"."totals" "xt" ON (("xt"."lenser_id" = "p"."id")))
     LEFT JOIN "reputation"."lenser_scores" "rs_elo" ON ((("rs_elo"."lenser_id" = "p"."id") AND ("rs_elo"."score_type" = 'elo'::"text"))))
     LEFT JOIN "reputation"."lenser_scores" "rs_cmp" ON ((("rs_cmp"."lenser_id" = "p"."id") AND ("rs_cmp"."score_type" = 'composite'::"text"))))
     LEFT JOIN "reputation"."contender_ratings" "cr" ON (("cr"."lenser_id" = "p"."id")))
  WHERE (("p"."status" = 'active'::"lensers"."lenser_status") AND ("p"."visibility" = 'public'::"lensers"."lenser_visibility") AND ("p"."deletion_requested_at" IS NULL))
  GROUP BY "p"."id", "p"."handle", "p"."display_name", "p"."avatar_url", "p"."type", "xt"."total_xp", "xt"."current_level", "rs_elo"."score", "rs_cmp"."score";


ALTER VIEW "xp"."v_leaderboard" OWNER TO "postgres";


COMMENT ON VIEW "xp"."v_leaderboard" IS 'XP + ELO leaderboard for LeaderboardPage. DENSE_RANK() computed server-side. Supports both xp_rank and elo_rank tabs. Active public profiles only. Paginate by total_xp DESC with cursor.';



CREATE OR REPLACE FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text" DEFAULT 'xp'::"text", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "xp"."v_leaderboard"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'reputation', 'lensers', 'public'
    AS $$
BEGIN
  IF p_order_by = 'elo' THEN
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY elo_score DESC, total_xp DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  ELSE
    RETURN QUERY
      SELECT * FROM xp.v_leaderboard
      ORDER BY total_xp DESC, elo_score DESC, lenser_id
      LIMIT  LEAST(COALESCE(p_limit, 50), 100)
      OFFSET GREATEST(COALESCE(p_offset, 0), 0);
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_leaderboard"("p_order_by" "text", "p_limit" integer, "p_offset" integer) IS 'Paginated leaderboard for LeaderboardPage. p_order_by: ''xp'' (default) sorts by total_xp, ''elo'' sorts by elo_score. LIMIT capped at 100. Uses offset pagination (simple for leaderboard UX).';



