CREATE OR REPLACE FUNCTION "public"."fn_post_global_message"("p_battle_id" "uuid", "p_body" "text", "p_sender_handle" "text", "p_sender_role" "text" DEFAULT 'lenser'::"text") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "sender_id" "uuid", "sender_handle" "text", "sender_role" "text", "body" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_sender_id uuid;
BEGIN
  v_sender_id := lensers.get_auth_lenser_id();
  IF v_sender_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  INSERT INTO battles.global_messages (battle_id, sender_id, sender_handle, sender_role, body)
  VALUES (p_battle_id, v_sender_id, p_sender_handle, p_sender_role, p_body)
  RETURNING
    battles.global_messages.id,
    battles.global_messages.battle_id,
    battles.global_messages.sender_id,
    battles.global_messages.sender_handle,
    battles.global_messages.sender_role,
    battles.global_messages.body,
    battles.global_messages.created_at;
END;
$$;


