CREATE OR REPLACE FUNCTION "public"."fn_xp_get_history"("p_lenser_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "action_key" "text", "xp" integer, "base_xp" integer, "source" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'lensers', 'auth'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  IF p_lenser_id IS NULL THEN
    SELECT id INTO v_lenser_id FROM lensers.profiles WHERE user_id = auth.uid();
  ELSE
    v_lenser_id := p_lenser_id;
  END IF;

  RETURN QUERY
  SELECT e.id, e.action_key::text, e.xp, e.base_xp, e.source::text, e.created_at
  FROM xp.events e
  WHERE e.lenser_id = v_lenser_id
  ORDER BY e.created_at DESC
  LIMIT LEAST(p_limit, 200);
END;
$$;


