    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'wallet'
    AS $$
  SELECT COALESCE(
    (SELECT balance FROM wallet.accounts WHERE lenser_id = p_lenser_id),
    0
  );
$$;


