CREATE OR REPLACE FUNCTION "xp"."on_battle_created"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'battles'
    AS $$
BEGIN
  -- On INSERT: skip if battle starts as draft
  -- On UPDATE: WHEN clause ensures OLD.status = 'draft' AND NEW.status != 'draft'
  IF TG_OP = 'INSERT' AND NEW.status = 'draft'::battles.battle_status_enum THEN
    RETURN NEW;
  END IF;

  -- Guard against double-award on UPDATE if XP was already given at INSERT
  IF TG_OP = 'UPDATE' THEN
    IF EXISTS (
      SELECT 1 FROM xp.events
      WHERE source_ref_type = 'battle'
        AND source_ref_id   = NEW.id
        AND lenser_id       = NEW.creator_lenser_id
        AND action_key      = 'BATTLE_CREATED'
        AND xp              > 0
    ) THEN
      RETURN NEW;
    END IF;
  END IF;

  PERFORM xp.apply(
    p_lenser_id       := NEW.creator_lenser_id,
    p_rule_key        := 'BATTLE_CREATED',
    p_source          := 'battle'::xp.source_enum,
    p_source_ref_type := 'battle',
    p_source_ref_id   := NEW.id,
    p_app_id          := '00000000-0000-0000-0000-000000000002'::uuid
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "xp"."on_battle_created"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."on_lens_created"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'lenses', 'content'
    AS $$
BEGIN
  -- Only award creation XP for publicly visible, published lenses
  IF NEW.visibility <> 'public'::content.visibility_enum
     OR NEW.status   <> 'published'::content.content_status THEN
    RETURN NEW;
  END IF;

  PERFORM xp.apply(
    p_lenser_id       := NEW.lenser_id,
    p_rule_key        := 'LENS_CREATED',
    p_source          := 'content'::xp.source_enum,
    p_source_ref_type := 'lens',
    p_source_ref_id   := NEW.id,
    p_app_id          := '00000000-0000-0000-0000-000000000001'::uuid
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "xp"."on_lens_created"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."on_lens_visibility_changed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'lenses', 'content'
    AS $$
DECLARE
  v_was_public boolean;
  v_now_public boolean;
BEGIN
  v_was_public := OLD.visibility = 'public'::content.visibility_enum
                  AND OLD.status  = 'published'::content.content_status;
  v_now_public := NEW.visibility = 'public'::content.visibility_enum
                  AND NEW.status  = 'published'::content.content_status;

  -- Transition: public+published → non-public → rollback creation XP
  IF v_was_public AND NOT v_now_public THEN
    PERFORM xp.rollback_content_xp('lens', NEW.id, NEW.lenser_id);

  -- Transition: non-public → public+published → re-award if no prior grant
  ELSIF NOT v_was_public AND v_now_public THEN
    IF NOT EXISTS (
      SELECT 1 FROM xp.events
      WHERE source_ref_type = 'lens'
        AND source_ref_id   = NEW.id
        AND lenser_id       = NEW.lenser_id
        AND action_key      = 'LENS_CREATED'
        AND xp              > 0
    ) THEN
      PERFORM xp.apply(
        p_lenser_id       := NEW.lenser_id,
        p_rule_key        := 'LENS_CREATED',
        p_source          := 'content'::xp.source_enum,
        p_source_ref_type := 'lens',
        p_source_ref_id   := NEW.id,
        p_app_id          := '00000000-0000-0000-0000-000000000001'::uuid
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "xp"."on_lens_visibility_changed"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."on_reaction_added"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'xp', 'content', 'lensers', 'public', 'auth'
    AS $$
declare
  v_thread_id uuid;
begin
  -- Resolve thread_id from reaction target
  if new.target_type = 'thread' then
    v_thread_id := new.target_id;

  elsif new.target_type = 'thread_reply' then
    select tr.thread_id
    into v_thread_id
    from content.thread_replies tr
    where tr.id = new.target_id;

  else
    -- prompt_template or others → ignore
    return new;
  end if;

  if v_thread_id is null then
    return new;
  end if;

  insert into analytics.tag_activity_events (
    tag_id,
    entity_type,
    entity_id,
    activity_type,
    actor_id
  )
  select
    tm.tag_id,
    'thread'::content.entity_type_enum,   -- ✅ ONLY trusted enum
    tm.entity_id,
    'reacted',
    new.user_id
  from content.tag_map tm
  where tm.entity_type = 'thread'::content.entity_type_enum
    and tm.entity_id = v_thread_id;

  return new;
end;
$$;


ALTER FUNCTION "xp"."on_reaction_added"() OWNER TO "postgres";


