BEGIN
  PERFORM xp.apply(
    p_lenser_id       := NEW.lenser_id,
    p_rule_key        := 'REACTION_GIVEN',
    p_source          := 'social'::xp.source_enum,
    p_source_ref_type := 'reaction',
    p_source_ref_id   := NEW.id,
    p_app_id          := '00000000-0000-0000-0000-000000000001'::uuid
  );
  RETURN NEW;
END;
$$;


