CREATE OR REPLACE FUNCTION "xp"."on_workflow_visibility_changed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'lenses'
    AS $$
BEGIN
  -- Transition: public → non-public → rollback creation XP
  IF OLD.visibility = 'public' AND NEW.visibility <> 'public' THEN
    PERFORM xp.rollback_content_xp('workflow', NEW.id, NEW.lenser_id);

  -- Transition: non-public → public → re-award if no prior grant
  ELSIF OLD.visibility <> 'public' AND NEW.visibility = 'public' THEN
    IF NOT EXISTS (
      SELECT 1 FROM xp.events
      WHERE source_ref_type = 'workflow'
        AND source_ref_id   = NEW.id
        AND lenser_id       = NEW.lenser_id
        AND action_key      = 'WORKFLOW_CREATED'
        AND xp              > 0
    ) THEN
      PERFORM xp.apply(
        p_lenser_id       := NEW.lenser_id,
        p_rule_key        := 'WORKFLOW_CREATED',
        p_source          := 'content'::xp.source_enum,
        p_source_ref_type := 'workflow',
        p_source_ref_id   := NEW.id,
        p_app_id          := '00000000-0000-0000-0000-000000000001'::uuid
      );
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


