CREATE OR REPLACE FUNCTION "xp"."rollback_content_xp"("p_source_ref_type" "text", "p_source_ref_id" "uuid", "p_lenser_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
DECLARE
  v_event_id uuid;
  v_count    integer := 0;
BEGIN
  -- Find all positive creation XP events for this content item.
  -- Exclude _ROLLBACK suffix entries (already compensated).
  FOR v_event_id IN
    SELECT id
    FROM xp.events
    WHERE source_ref_type = p_source_ref_type
      AND source_ref_id   = p_source_ref_id
      AND lenser_id       = p_lenser_id
      AND xp              > 0
      AND action_key      NOT LIKE '%_ROLLBACK'
  LOOP
    PERFORM xp.rollback_event(v_event_id, 'content_visibility_change');
    v_count := v_count + 1;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "xp"."rollback_content_xp"("p_source_ref_type" "text", "p_source_ref_id" "uuid", "p_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."rollback_event"("p_event_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS TABLE("total_xp" bigint, "level" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'lensers', 'public'
    AS $$DECLARE
  v_event xp.events%ROWTYPE;
  v_total_after bigint;
  v_level int;
BEGIN
  -------------------------------------------------------------------
  -- 1) LOAD ORIGINAL EVENT
  -------------------------------------------------------------------
  SELECT *
  INTO v_event
  FROM xp.events e
  WHERE e.id = p_event_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'XP event not found: %', p_event_id;
  END IF;


  -------------------------------------------------------------------
  -- 2) INSERT COMPENSATING NEGATIVE EVENT
  -------------------------------------------------------------------
  INSERT INTO xp.events (
    lenser_id,
    app_id,
    rule_id,
    action_key,
    xp,
    base_xp,
    source,
    source_ref_type,
    source_ref_id,
    signature,
    meta
  )
  VALUES (
    v_event.lenser_id,
    v_event.app_id,
    v_event.rule_id,
    v_event.action_key || '_ROLLBACK',
    -v_event.xp,
    -v_event.base_xp,
    'system',                        -- system-originated rollback
    'xp_event',
    v_event.id,
    NULL,
    jsonb_build_object(
      'rollback_of', v_event.id::text,
      'rollback_reason', p_reason
    )
  );


  -------------------------------------------------------------------
  -- 3) UPDATE XP TOTALS (SUBTRACT ORIGINAL XP)
  -------------------------------------------------------------------
  UPDATE xp.totals t
  SET total_xp = GREATEST(t.total_xp - v_event.xp, 0),
      updated_at = now()
  WHERE t.lenser_id = v_event.lenser_id
    AND t.app_id = v_event.app_id
  RETURNING t.total_xp INTO v_total_after;

  IF NOT FOUND THEN
    -- No totals row: nothing to rollback
    v_total_after := 0;
  END IF;


  -------------------------------------------------------------------
  -- 4) RECALCULATE LEVEL
  -------------------------------------------------------------------
  SELECT lvl.level
  INTO v_level
  FROM xp.levels lvl
  WHERE lvl.app_id = v_event.app_id
    AND v_total_after >= lvl.min_total_xp
    AND v_total_after <= lvl.max_total_xp
  LIMIT 1;

  IF v_level IS NULL THEN
    v_level := 1;
  END IF;


  -------------------------------------------------------------------
  -- 5) UPDATE STORED LEVEL
  -------------------------------------------------------------------
  UPDATE xp.totals
  SET current_level = v_level,
      updated_at = now()
  WHERE lenser_id = v_event.lenser_id
    AND app_id = v_event.app_id;


  -------------------------------------------------------------------
  -- 6) RETURN NEW STATE
  -------------------------------------------------------------------
  RETURN QUERY
  SELECT v_total_after AS total_xp,
         v_level       AS level;

END;$$;


ALTER FUNCTION "xp"."rollback_event"("p_event_id" "uuid", "p_reason" "text") OWNER TO "postgres";


