);


ALTER TABLE "audit"."admin_actions" OWNER TO "postgres";


COMMENT ON TABLE "audit"."admin_actions" IS 'Admin operations audit log. Append-only. Every admin action must be logged here. KEPT SEPARATE from audit.events because: (1) admin_lenser_id is NOT NULL — all admin actions require a named human actor; (2) reason column is required for all admin actions (compliance requirement); (3) distinct RLS: only service_role reads admin_actions (audit.events has broader read policies); (4) potential for distinct retention rules (admin logs may need longer retention than general events). If all four distinctions are resolved, migrate rows into audit.events and drop this table.';



CREATE TABLE IF NOT EXISTS "audit"."attestations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "entity_type" "text" NOT NULL,
    "entity_id" "uuid" NOT NULL,
    "attested_by" "uuid" NOT NULL,
    "attestation_type" "text" NOT NULL,
    "proof_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "attestations_type_check" CHECK (("attestation_type" = ANY (ARRAY['battle_published'::"text", 'battle_finalized'::"text", 'benchmark_frozen'::"text", 'agent_created'::"text", 'agent_suspended'::"text", 'result_invalidated'::"text"])))
);


ALTER TABLE "audit"."attestations" OWNER TO "postgres";


COMMENT ON TABLE "audit"."attestations" IS 'Append-only attestation records for key platform lifecycle events. Created exclusively via SECURITY DEFINER RPCs. proof_payload captures the relevant context (snapshot_hash, handle, etc.) for future audit replay.';



CREATE TABLE IF NOT EXISTS "audit"."disputes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "target_entity_type" "text" NOT NULL,
    "target_entity_id" "uuid" NOT NULL,
    "disputer_lenser_id" "uuid" NOT NULL,
    "reason" "text" NOT NULL,
    "evidence_urls" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "resolved_by" "uuid",
    "resolved_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "disputes_resolve_consistency" CHECK ((("status" = ANY (ARRAY['resolved'::"text", 'dismissed'::"text"])) = (("resolved_by" IS NOT NULL) AND ("resolved_at" IS NOT NULL)))),
    CONSTRAINT "disputes_status_check" CHECK (("status" = ANY (ARRAY['open'::"text", 'under_review'::"text", 'resolved'::"text", 'dismissed'::"text"])))
);


ALTER TABLE "audit"."disputes" OWNER TO "postgres";


COMMENT ON TABLE "audit"."disputes" IS 'Appeal trail for moderation and benchmark decisions. Mutable: status transitions from open → under_review → resolved/dismissed. A dispute does not modify the original target record — it creates a parallel review record alongside the immutable audit trail.';



CREATE TABLE IF NOT EXISTS "audit"."events" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "occurred_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "event_type" "text" NOT NULL,
    "entity_schema" "text",
    "entity_table" "text",
    "entity_id" "uuid",
    "actor_lenser_id" "uuid",
    "actor_actor_id" "uuid",
    "ip_hash" "text",
    "user_agent_hash" "text",
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "severity" "text" DEFAULT 'info'::"text" NOT NULL,
    "actor_type" "text",
    "actor_id" "uuid",
    CONSTRAINT "events_actor_type_check" CHECK ((("actor_type" IS NULL) OR ("actor_type" = ANY (ARRAY['lenser'::"text", 'ai_actor'::"text", 'system'::"text"])))),
    CONSTRAINT "events_no_dual_actor" CHECK ((NOT (("actor_lenser_id" IS NOT NULL) AND ("actor_actor_id" IS NOT NULL)))),
    CONSTRAINT "events_severity_check" CHECK (("severity" = ANY (ARRAY['info'::"text", 'warn'::"text", 'error'::"text", 'critical'::"text"])))
);


ALTER TABLE "audit"."events" OWNER TO "postgres";


COMMENT ON TABLE "audit"."events" IS 'Core immutable event log. Append-only. Partition by occurred_at when row count exceeds ~10M rows.';



COMMENT ON COLUMN "audit"."events"."actor_lenser_id" IS 'DEPRECATED: use actor_type=''lenser'' + actor_id instead. Will be removed after all callers migrate to log_event_v2.';



COMMENT ON COLUMN "audit"."events"."actor_actor_id" IS 'DEPRECATED: use actor_type=''ai_actor'' + actor_id instead. Will be removed after all callers migrate to log_event_v2.';



COMMENT ON COLUMN "audit"."events"."ip_hash" IS 'SHA-256 of client IP. GDPR-safe: not reversible without rainbow table. Never store raw IP.';



COMMENT ON COLUMN "audit"."events"."payload" IS 'Non-sensitive event details. MUST NOT contain API keys, tokens, or PII.';



COMMENT ON COLUMN "audit"."events"."actor_type" IS 'Unified actor type: ''lenser'', ''ai_actor'', or ''system''. Supersedes actor_lenser_id + actor_actor_id split columns.';



COMMENT ON COLUMN "audit"."events"."actor_id" IS 'UUID of the unified actor. Interpret per actor_type.';



CREATE TABLE IF NOT EXISTS "audit"."hash_chains" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_id" "uuid" NOT NULL,
    "prev_hash" "text",
    "payload_hash" "text" NOT NULL,
    "sequence_no" bigint NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "audit"."hash_chains" OWNER TO "postgres";


COMMENT ON TABLE "audit"."hash_chains" IS 'Append-only hash chain over audit.events. Provides tamper-evident ordering. sequence_no is monotonically increasing across the entire chain. Partition by sequence_no range when it exceeds ~5M rows.';



CREATE TABLE IF NOT EXISTS "audit"."idempotency_keys" (
    "scope" "text" NOT NULL,
    "idempotency_key" "text" NOT NULL,
    "reference_type" "text",
    "reference_id" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "audit"."idempotency_keys" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "audit"."idempotency_requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "idempotency_key" "text" NOT NULL,
    "idempotency_key_hash" "text" NOT NULL,
    "account_id" "uuid" NOT NULL,
    "workspace_id" "uuid",
    "actor_chainer_id" "uuid" NOT NULL,
    "route_signature" "text" NOT NULL,
    "method" "text" NOT NULL,
    "request_fingerprint" "text" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "http_status" integer,
    "response_headers" "jsonb",
    "response_body" "jsonb",
    "error_body" "jsonb",
    "provider_name" "text",
    "provider_operation_key" "text",
    "provider_request_id" "text",
    "locked_until" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "expires_at" timestamp with time zone DEFAULT ("now"() + '24:00:00'::interval) NOT NULL,
    CONSTRAINT "idempotency_requests_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'completed'::"text", 'failed'::"text"])))
);


ALTER TABLE "audit"."idempotency_requests" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "audit"."moderation_decisions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "occurred_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "target_entity_schema" "text" NOT NULL,
    "target_entity_table" "text" NOT NULL,
    "target_entity_id" "uuid" NOT NULL,
    "decision_type" "text" NOT NULL,
    "reason" "text",
    "evidence_urls" "text"[],
    "moderator_lenser_id" "uuid",
    "is_ai_moderated" boolean DEFAULT false NOT NULL,
    "ai_confidence" numeric(5,4),
    "appeal_deadline_at" timestamp with time zone,
    "is_appealed" boolean DEFAULT false NOT NULL,
    "appealed_at" timestamp with time zone,
    "appeal_outcome" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "moderation_accountability_check" CHECK ((("is_ai_moderated" = true) OR ("moderator_lenser_id" IS NOT NULL))),
    CONSTRAINT "moderation_decisions_ai_confidence_range" CHECK ((("ai_confidence" IS NULL) OR (("ai_confidence" >= (0)::numeric) AND ("ai_confidence" <= (1)::numeric)))),
    CONSTRAINT "moderation_decisions_appeal_outcome_check" CHECK ((("appeal_outcome" IS NULL) OR ("appeal_outcome" = ANY (ARRAY['upheld'::"text", 'overturned'::"text", 'pending'::"text"])))),
    CONSTRAINT "moderation_decisions_type_check" CHECK (("decision_type" = ANY (ARRAY['approved'::"text", 'rejected'::"text", 'flagged'::"text", 'removed'::"text", 'restored'::"text", 'warned'::"text"]))),
    CONSTRAINT "moderation_no_dual_actor" CHECK ((NOT (("is_ai_moderated" = true) AND ("moderator_lenser_id" IS NOT NULL))))
);


ALTER TABLE "audit"."moderation_decisions" OWNER TO "postgres";


COMMENT ON TABLE "audit"."moderation_decisions" IS 'Moderation log for content, battles, and actors. Includes appeal tracking.';



COMMENT ON CONSTRAINT "moderation_accountability_check" ON "audit"."moderation_decisions" IS 'Every human-moderated decision (is_ai_moderated=false) must name a moderator. Prevents unattributed decisions that create legal/compliance risk.';



COMMENT ON CONSTRAINT "moderation_no_dual_actor" ON "audit"."moderation_decisions" IS 'AI-moderated decisions must not also carry a human moderator_lenser_id. Prevents semantically contradictory attribution.';



CREATE TABLE IF NOT EXISTS "audit"."security_events" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
