);


ALTER TABLE "audit"."security_events" OWNER TO "postgres";


COMMENT ON TABLE "audit"."security_events" IS 'BYOK lifecycle and security event log. Append-only. key_ref_id references agents.byok_key_refs; vault_secret_name is never stored here.';



COMMENT ON COLUMN "audit"."security_events"."event_type" IS 'Security event category. Typed as audit.security_event_type_enum. Extend by: ALTER TYPE audit.security_event_type_enum ADD VALUE ''new_value''.';



COMMENT ON COLUMN "audit"."security_events"."metadata" IS 'Non-sensitive metadata only. No vault names, no raw keys, no tokens.';



