    "pool_id" "uuid" NOT NULL,
    "recipient_lenser_id" "uuid" NOT NULL,
    "amount_credits" bigint NOT NULL,
    "platform_fee_credits" bigint DEFAULT 0 NOT NULL,
    "payout_type" "text" NOT NULL,
    "external_tx_ref" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "sponsorship_payouts_amount_check" CHECK (("amount_credits" > 0)),
    CONSTRAINT "sponsorship_payouts_fee_check" CHECK (("platform_fee_credits" >= 0)),
    CONSTRAINT "sponsorship_payouts_type_check" CHECK (("payout_type" = ANY (ARRAY['winner'::"text", 'runner_up'::"text", 'refund'::"text", 'platform_fee'::"text"])))
);


ALTER TABLE "battles"."sponsorship_payouts" OWNER TO "postgres";


COMMENT ON TABLE "battles"."sponsorship_payouts" IS 'Credit payouts from sponsorship pool after battle closes. Includes winner, runner_up, refund, and platform_fee entries.';



CREATE TABLE IF NOT EXISTS "battles"."sponsorship_pools" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "total_credits" bigint DEFAULT 0 NOT NULL,
    "platform_fee_pct" smallint DEFAULT 10 NOT NULL,
    "status" "battles"."sponsorship_pool_status_enum" DEFAULT 'open'::"battles"."sponsorship_pool_status_enum" NOT NULL,
    "locked_at" timestamp with time zone,
    "distributed_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "payout_mode" "text" DEFAULT 'credits_only'::"text" NOT NULL,
    "legal_jurisdiction" "text",
    CONSTRAINT "sponsorship_payout_mode_check" CHECK (("payout_mode" = ANY (ARRAY['credits_only'::"text", 'fiat_optional'::"text"]))),
    CONSTRAINT "sponsorship_pools_platform_fee_pct_check" CHECK ((("platform_fee_pct" >= 0) AND ("platform_fee_pct" <= 50))),
    CONSTRAINT "sponsorship_pools_total_credits_check" CHECK (("total_credits" >= 0))
);


ALTER TABLE "battles"."sponsorship_pools" OWNER TO "postgres";


COMMENT ON TABLE "battles"."sponsorship_pools" IS 'Credit pool for battle sponsorship. platform_fee_pct is the percentage taken by the platform on distribution. Managed by CF Worker only.';



COMMENT ON COLUMN "battles"."sponsorship_pools"."payout_mode" IS 'credits_only = platform-internal credits only (legally safe default). fiat_optional = requires explicit legal review before enabling. When AI wins a battle, credits go to the human lenser who registered the AI actor — no autonomous AI payout.';



COMMENT ON COLUMN "battles"."sponsorship_pools"."legal_jurisdiction" IS 'Optional ISO 3166-1 alpha-2 country code for the jurisdiction governing this pool. Required before fiat_optional can be enabled.';



CREATE TABLE IF NOT EXISTS "battles"."stream_recordings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "contender_id" "uuid" NOT NULL,
