    "content_type" "text" DEFAULT 'text'::"text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "stream_recordings_slot_check" CHECK (("slot" = ANY (ARRAY['A'::"text", 'B'::"text"])))
);


ALTER TABLE "battles"."stream_recordings" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."templates" (
