    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "tool_registry_content_type_check" CHECK (("content_type" = ANY (ARRAY['text'::"text", 'code'::"text", 'poem'::"text", 'drawing'::"text", 'image'::"text", 'video'::"text", 'audio'::"text", 'workflow'::"text", 'map'::"text", 'avatar'::"text", 'image_edit'::"text", 'kaggle'::"text"])))
);


ALTER TABLE "battles"."tool_registry" OWNER TO "postgres";


CREATE OR REPLACE VIEW "battles"."v_battle_feed_item" AS
 SELECT "b"."id",
    "b"."slug",
    "b"."title",
    "b"."status",
    "b"."battle_type",
    "b"."voter_eligibility",
    "b"."total_vote_count",
    "b"."published_at",
    "b"."voting_opens_at",
    "b"."voting_closes_at",
    "b"."winner_contender_id",
    "b"."created_at",
    "ca"."id" AS "contender_a_id",
    "ca"."display_name" AS "contender_a_name",
    "ca"."contender_type" AS "contender_a_type",
    "cb"."id" AS "contender_b_id",
    "cb"."display_name" AS "contender_b_name",
    "cb"."contender_type" AS "contender_b_type",
        CASE
            WHEN ("b"."winner_contender_id" = "ca"."id") THEN 'A'::"text"
            WHEN ("b"."winner_contender_id" = "cb"."id") THEN 'B'::"text"
            ELSE NULL::"text"
        END AS "winner_slot"
   FROM (("battles"."battles" "b"
     LEFT JOIN "battles"."contenders" "ca" ON ((("ca"."battle_id" = "b"."id") AND ("ca"."slot" = 'A'::"bpchar") AND ("ca"."contender_status" = 'active'::"text"))))
     LEFT JOIN "battles"."contenders" "cb" ON ((("cb"."battle_id" = "b"."id") AND ("cb"."slot" = 'B'::"bpchar") AND ("cb"."contender_status" = 'active'::"text"))))
  WHERE (("b"."deleted_at" IS NULL) AND ("b"."status" = ANY (ARRAY['voting'::"battles"."battle_status_enum", 'scoring'::"battles"."battle_status_enum", 'closed'::"battles"."battle_status_enum", 'published'::"battles"."battle_status_enum", 'archived'::"battles"."battle_status_enum"])));


ALTER VIEW "battles"."v_battle_feed_item" OWNER TO "postgres";


COMMENT ON VIEW "battles"."v_battle_feed_item" IS 'Denormalized battle card for BattlesFeedPage. Used by fn_get_battles_feed. Includes contender names and winner_slot but not submissions or vote details. Only exposes post-draft statuses (voting, scoring, closed, published, archived).';



CREATE TABLE IF NOT EXISTS "battles"."vote_choices" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "vote_id" "uuid" NOT NULL,
