);


ALTER TABLE "battles"."vote_choices" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."votes" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
