CREATE OR REPLACE VIEW "lensers"."vw_lensers_score" AS
 SELECT "lp"."id" AS "lenser_id",
    "lp"."handle",
    "lp"."display_name",
    "lp"."avatar_url",
    COALESCE("xt"."total_xp", (0)::numeric) AS "total_xp",
    COALESCE("xt"."current_level", 1) AS "current_level",
    (((0.7)::double precision * "log"(GREATEST((1.0)::double precision, (COALESCE("xt"."total_xp", (0)::numeric))::double precision))) + ((0.3)::double precision * "log"(GREATEST((1.0)::double precision, (COALESCE("re7"."recent_reactions", (0)::bigint))::double precision)))) AS "lenser_score"
   FROM (("lensers"."profiles" "lp"
     LEFT JOIN ( SELECT "totals"."lenser_id",
            "sum"("totals"."total_xp") AS "total_xp",
            "max"("totals"."current_level") AS "current_level"
           FROM "xp"."totals"
          GROUP BY "totals"."lenser_id") "xt" ON (("xt"."lenser_id" = "lp"."id")))
     LEFT JOIN ( SELECT "all_recent"."lenser_id",
            "count"(*) AS "recent_reactions"
           FROM ( SELECT "t"."lenser_id"
                   FROM ("content"."reactions" "r"
                     JOIN "content"."threads" "t" ON (("t"."id" = "r"."entity_id")))
                  WHERE (("r"."created_at" > ("now"() - '7 days'::interval)) AND ("r"."entity_type" = 'thread'::"content"."entity_type_enum"))
                UNION ALL
                 SELECT "pt"."lenser_id"
                   FROM ("content"."reactions" "r"
                     JOIN "lenses"."lenses" "pt" ON (("pt"."id" = "r"."entity_id")))
                  WHERE (("r"."created_at" > ("now"() - '7 days'::interval)) AND ("r"."entity_type" = 'lens'::"content"."entity_type_enum"))) "all_recent"
          GROUP BY "all_recent"."lenser_id") "re7" ON (("re7"."lenser_id" = "lp"."id")))
  WHERE (("lp"."status" = 'active'::"lensers"."lenser_status") AND ("lp"."visibility" = 'public'::"lensers"."lenser_visibility") AND ("lp"."deletion_requested_at" IS NULL));


ALTER VIEW "lensers"."vw_lensers_score" OWNER TO "postgres";


COMMENT ON VIEW "lensers"."vw_lensers_score" IS 'Lenser scoring view for recommendation and discovery ranking. Combines XP totals with recent reaction activity (7-day window). Updated to use unified content.reactions table (migration 20260440000008).';



