CREATE OR REPLACE VIEW "public"."vw_xp_leaderboard_global" WITH ("security_invoker"='on') AS
 WITH "ranked" AS (
         SELECT "t"."app_id",
            "t"."lenser_id",
            "t"."total_xp",
            "t"."current_level",
            "rank"() OVER (PARTITION BY "t"."app_id" ORDER BY "t"."total_xp" DESC, "t"."lenser_id") AS "rank"
           FROM "xp"."totals" "t"
        )
 SELECT "r"."app_id",
    "r"."rank",
    "r"."lenser_id",
    "r"."total_xp",
    "r"."current_level",
    "jsonb_build_object"('display_name', "l"."display_name", 'handle', "l"."handle", 'avatar_url', "l"."avatar_url") AS "user"
   FROM ("ranked" "r"
     JOIN "lensers"."profiles" "l" ON (("l"."id" = "r"."lenser_id")))
  WHERE ("r"."rank" <= 100);


