CREATE OR REPLACE VIEW "status"."v_public_components" WITH ("security_invoker"='true') AS
 SELECT "c"."id",
    "c"."slug",
    "c"."name",
    "c"."description",
    "c"."current_status",
    "c"."indicator",
    "c"."service_id",
    "c"."payload",
    "c"."sort_order",
    "c"."is_public",
    "c"."created_at",
    "c"."updated_at"
   FROM ("status"."components" "c"
     JOIN "status"."services" "s" ON (("s"."id" = "c"."service_id")))
  WHERE (("c"."is_public" = true) AND ("s"."is_public" = true));


