CREATE OR REPLACE VIEW "lenses"."vw_lens_version_history" AS
 SELECT "v"."id",
    "v"."lens_id",
    "v"."version_number",
    "v"."template_body",
    "v"."status",
    "v"."changelog",
    "v"."parent_version_id",
    "v"."published_at",
    "v"."created_at",
    ("count"("vp"."id"))::integer AS "parameter_count"
   FROM ("lenses"."versions" "v"
     LEFT JOIN "lenses"."version_parameters" "vp" ON (("vp"."version_id" = "v"."id")))
  GROUP BY "v"."id";



