  create policy "cities_select_public"
  on "core"."cities"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "countries_select_public"
  on "core"."countries"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "currencies_select_public"
  on "core"."currencies"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "regions_select_public"
  on "core"."regions"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "states_select_public"
  on "core"."states"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "subregions_select_public"
  on "core"."subregions"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "public read components"
  on "status"."components"
  as permissive
  for select
  to anon, authenticated
using (((is_public = true) AND (EXISTS ( SELECT 1
   FROM status.services s
  WHERE ((s.id = components.service_id) AND (s.is_public = true))))));



  create policy "public read daily_snapshots"
  on "status"."daily_snapshots"
  as permissive
  for select
  to anon, authenticated
using (true);



  create policy "public read incident_updates"
  on "status"."incident_updates"
  as permissive
  for select
  to anon, authenticated
using ((EXISTS ( SELECT 1
   FROM (status.incidents i
     LEFT JOIN status.services s ON ((s.id = i.service_id)))
  WHERE ((i.id = incident_updates.incident_id) AND (i.published = true) AND ((i.service_id IS NULL) OR (s.is_public = true))))));



  create policy "public read incidents"
  on "status"."incidents"
  as permissive
  for select
  to anon, authenticated
using (((published = true) AND ((service_id IS NULL) OR (EXISTS ( SELECT 1
   FROM status.services s
  WHERE ((s.id = incidents.service_id) AND (s.is_public = true)))))));



  create policy "public read maintenance_windows"
  on "status"."maintenance_windows"
  as permissive
  for select
  to anon, authenticated
using (((published = true) AND ((service_id IS NULL) OR (EXISTS ( SELECT 1
   FROM status.services s
  WHERE ((s.id = maintenance_windows.service_id) AND (s.is_public = true)))))));



  create policy "public read services"
  on "status"."services"
  as permissive
  for select
  to anon, authenticated
using ((is_public = true));



  create policy "public read uptime_rollups"
  on "status"."uptime_rollups"
  as permissive
  for select
  to anon, authenticated
using (true);


CREATE TRIGGER trg_login_consolidated AFTER UPDATE OF last_sign_in_at ON auth.users FOR EACH ROW EXECUTE FUNCTION lensers.trg_log_login_from_auth();


  create policy "auth_delete_own_objects"
  on "storage"."objects"
  as permissive
  for delete
  to authenticated
using (((storage.foldername(name))[1] = (auth.uid())::text));



  create policy "auth_read_own_artifacts"
  on "storage"."objects"
  as permissive
  for select
  to authenticated
using (((bucket_id = 'artifacts'::text) AND ((storage.foldername(name))[1] = (auth.uid())::text)));



  create policy "auth_read_own_lens_resources"
  on "storage"."objects"
  as permissive
  for select
  to authenticated
using (((bucket_id = 'lens-resources'::text) AND ((storage.foldername(name))[1] = (auth.uid())::text)));



  create policy "auth_read_own_user_media"
  on "storage"."objects"
  as permissive
  for select
  to authenticated
using (((bucket_id = 'user-media'::text) AND ((storage.foldername(name))[1] = (auth.uid())::text)));



  create policy "auth_upload_artifacts"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check ((bucket_id = 'artifacts'::text));



  create policy "auth_upload_lens_resources"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check ((bucket_id = 'lens-resources'::text));



  create policy "auth_upload_public_assets"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check ((bucket_id = 'public-assets'::text));



  create policy "auth_upload_user_media"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check ((bucket_id = 'user-media'::text));



  create policy "public_read_public_assets"
  on "storage"."objects"
  as permissive
  for select
  to anon, authenticated
using ((bucket_id = 'public-assets'::text));
